376     // `xor` is negatible if one of its operands is invertible.
377     // FIXME: InstCombineInverter? But how to connect Inverter and Negator?
378     if (auto *C = dyn_cast<Constant>(I->getOperand(1))) {
379       Value *Xor = Builder.CreateXor(I->getOperand(0), ConstantExpr::getNot(C));
