392     } else if (Value *NegOp0 = negate(I->getOperand(0), Depth + 1)) {
393       NegatedOp = NegOp0;
394       OtherOp = I->getOperand(1);
395     } else
396       // Can't negate either of them.
397       return nullptr;
398     return Builder.CreateMul(NegatedOp, OtherOp, I->getName() + ".neg");
