407 LLVM_NODISCARD Value *Negator::negate(Value *V, unsigned Depth) {
408   NegatorMaxDepthVisited.updateMax(Depth);
409   ++NegatorNumValuesVisited;
410 
411 #if LLVM_ENABLE_STATS
412   ++NumValuesVisitedInThisNegator;
413 #endif
414 
415 #ifndef NDEBUG
416   // We can't ever have a Value with such an address.
417   Value *Placeholder = reinterpret_cast<Value *>(static_cast<uintptr_t>(-1));
418 #endif
419 
420   // Did we already try to negate this value?
421   auto NegationsCacheIterator = NegationsCache.find(V);
422   if (NegationsCacheIterator != NegationsCache.end()) {
423     ++NegatorNumNegationsFoundInCache;
424     Value *NegatedV = NegationsCacheIterator->second;
425     assert(NegatedV != Placeholder && "Encountered a cycle during negation.");
426     return NegatedV;
427   }
428 
429 #ifndef NDEBUG
430   // We did not find a cached result for negation of V. While there,
431   // let's temporairly cache a placeholder value, with the idea that if later
432   // during negation we fetch it from cache, we'll know we're in a cycle.
433   NegationsCache[V] = Placeholder;
434 #endif
435 
436   // No luck. Try negating it for real.
437   Value *NegatedV = visitImpl(V, Depth);
438   // And cache the (real) result for the future.
439   NegationsCache[V] = NegatedV;
440 
441   return NegatedV;
442 }
