444 LLVM_NODISCARD Optional<Negator::Result> Negator::run(Value *Root) {
445   Value *Negated = negate(Root, /*Depth=*/0);
446   if (!Negated) {
447     // We must cleanup newly-inserted instructions, to avoid any potential
448     // endless combine looping.
449     llvm::for_each(llvm::reverse(NewInstructions),
450                    [&](Instruction *I) { I->eraseFromParent(); });
451     return llvm::None;
452   }
453   return std::make_pair(ArrayRef<Instruction *>(NewInstructions), Negated);
454 }
