456 LLVM_NODISCARD Value *Negator::Negate(bool LHSIsZero, Value *Root,
457                                       InstCombinerImpl &IC) {
458   ++NegatorTotalNegationsAttempted;
459   LLVM_DEBUG(dbgs() << "Negator: attempting to sink negation into " << *Root
460                     << "\n");
461 
462   if (!NegatorEnabled || !DebugCounter::shouldExecute(NegatorCounter))
463     return nullptr;
464 
465   Negator N(Root->getContext(), IC.getDataLayout(), IC.getAssumptionCache(),
466             IC.getDominatorTree(), LHSIsZero);
467   Optional<Result> Res = N.run(Root);
468   if (!Res) { // Negation failed.
469     LLVM_DEBUG(dbgs() << "Negator: failed to sink negation into " << *Root
470                       << "\n");
471     return nullptr;
472   }
473 
474   LLVM_DEBUG(dbgs() << "Negator: successfully sunk negation into " << *Root
475                     << "\n         NEW: " << *Res->second << "\n");
476   ++NegatorNumTreesNegated;
477 
478   // We must temporarily unset the 'current' insertion point and DebugLoc of the
479   // InstCombine's IRBuilder so that it won't interfere with the ones we have
480   // already specified when producing negated instructions.
481   InstCombiner::BuilderTy::InsertPointGuard Guard(IC.Builder);
482   IC.Builder.ClearInsertionPoint();
483   IC.Builder.SetCurrentDebugLocation(DebugLoc());
484 
485   // And finally, we must add newly-created instructions into the InstCombine's
486   // worklist (in a proper order!) so it can attempt to combine them.
487   LLVM_DEBUG(dbgs() << "Negator: Propagating " << Res->first.size()
488                     << " instrs to InstCombine\n");
489   NegatorMaxInstructionsCreated.updateMax(Res->first.size());
490   NegatorNumInstructionsNegatedSuccess += Res->first.size();
491 
492   // They are in def-use order, so nothing fancy, just insert them in order.
493   llvm::for_each(Res->first,
494                  [&](Instruction *I) { IC.Builder.Insert(I, I->getName()); });
495 
496   // And return the new root.
497   return Res->second;
498 }
