1152 static Value *simplifyWithOpReplaced(Value *V, Value *Op, Value *ReplaceOp,
1153                                      const SimplifyQuery &Q) {
1154   // If this is a binary operator, try to simplify it with the replaced op
1155   // because we know Op and ReplaceOp are equivalant.
1156   // For example: V = X + 1, Op = X, ReplaceOp = 42
1157   // Simplifies as: add(42, 1) --> 43
1158   if (auto *BO = dyn_cast<BinaryOperator>(V)) {
1159     if (BO->getOperand(0) == Op)
1160       return SimplifyBinOp(BO->getOpcode(), ReplaceOp, BO->getOperand(1), Q);
1161     if (BO->getOperand(1) == Op)
1162       return SimplifyBinOp(BO->getOpcode(), BO->getOperand(0), ReplaceOp, Q);
1163   }
1164 
1165   return nullptr;
1166 }
