1168 /// If we have a select with an equality comparison, then we know the value in
1169 /// one of the arms of the select. See if substituting this value into an arm
1170 /// and simplifying the result yields the same value as the other arm.
1171 ///
1172 /// To make this transform safe, we must drop poison-generating flags
1173 /// (nsw, etc) if we simplified to a binop because the select may be guarding
1174 /// that poison from propagating. If the existing binop already had no
1175 /// poison-generating flags, then this transform can be done by instsimplify.
1176 ///
1177 /// Consider:
1178 ///   %cmp = icmp eq i32 %x, 2147483647
1179 ///   %add = add nsw i32 %x, 1
1180 ///   %sel = select i1 %cmp, i32 -2147483648, i32 %add
1181 ///
1182 /// We can't replace %sel with %add unless we strip away the flags.
1183 /// TODO: Wrapping flags could be preserved in some cases with better analysis.
1184 static Value *foldSelectValueEquivalence(SelectInst &Sel, ICmpInst &Cmp,
1185                                          const SimplifyQuery &Q) {
1186   if (!Cmp.isEquality())
1187     return nullptr;
1188 
1189   // Canonicalize the pattern to ICMP_EQ by swapping the select operands.
1190   Value *TrueVal = Sel.getTrueValue(), *FalseVal = Sel.getFalseValue();
1191   if (Cmp.getPredicate() == ICmpInst::ICMP_NE)
1192     std::swap(TrueVal, FalseVal);
1193 
1194   // Try each equivalence substitution possibility.
1195   // We have an 'EQ' comparison, so the select's false value will propagate.
1196   // Example:
1197   // (X == 42) ? 43 : (X + 1) --> (X == 42) ? (X + 1) : (X + 1) --> X + 1
1198   // (X == 42) ? (X + 1) : 43 --> (X == 42) ? (42 + 1) : 43 --> 43
1199   Value *CmpLHS = Cmp.getOperand(0), *CmpRHS = Cmp.getOperand(1);
1200   if (simplifyWithOpReplaced(FalseVal, CmpLHS, CmpRHS, Q) == TrueVal ||
1201       simplifyWithOpReplaced(FalseVal, CmpRHS, CmpLHS, Q) == TrueVal ||
1202       simplifyWithOpReplaced(TrueVal, CmpLHS, CmpRHS, Q) == FalseVal ||
1203       simplifyWithOpReplaced(TrueVal, CmpRHS, CmpLHS, Q) == FalseVal) {
1204     if (auto *FalseInst = dyn_cast<Instruction>(FalseVal))
1205       FalseInst->dropPoisonGeneratingFlags();
1206     return FalseVal;
1207   }
1208   return nullptr;
1209 }
